exercises.solution_code:
#include <iostream>
#include <string>

struct Sensor {
    std::string label;
    int& ctor_ref;
    int& copy_ref;

    Sensor(const std::string& lbl, int& ctor_count, int& copy_count)
        : label{lbl}, ctor_ref{ctor_count}, copy_ref{copy_count} {
        ++ctor_ref;
    }

    Sensor(const Sensor& other)
        : label{other.label}, ctor_ref{other.ctor_ref}, copy_ref{other.copy_ref} {
        ++copy_ref;
    }
};

Sensor make_sensor(int& ctor_count, int& copy_count) {
    return Sensor{"beta", ctor_count, copy_count};
}

int main() {
    int ctor_count{0};
    int copy_count{0};

    Sensor a{"alpha", ctor_count, copy_count};
    Sensor b = make_sensor(ctor_count, copy_count);
    Sensor c = a;

    int n{};
    std::cin >> n;

    for (int i = 0; i < n; ++i) {
        Sensor tmp = a;
    }

    std::cout << "Constructor calls: "     << ctor_count << '\n';
    std::cout << "Copy constructor calls: " << copy_count << '\n';
}

