exercises.solution_code:
#include <iostream>
#include <format>

struct Point {
    int x{};
    int y{};

    Point(int px, int py) : x{px}, y{py} {
        std::cout << std::format("Constructed ({},{})\n", x, y);
    }

    Point(const Point& other) : x{other.x}, y{other.y} {
        std::cout << "Copied\n";
    }
};

Point midpoint(Point a, Point b) {
    return Point{ (a.x + b.x) / 2, (a.y + b.y) / 2 };
}

int main() {
    int x1{}, y1{}, x2{}, y2{};
    std::cin >> x1 >> y1 >> x2 >> y2;

    Point p{x1, y1};
    Point q{x2, y2};
    Point m = midpoint(p, q);
    std::cout << std::format("Midpoint: ({},{})\n", m.x, m.y);
}
